import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define the CUDA kernel for matrix-vector multiplication
cuda_code = """
#include <torch/extension.h>

__global__ void matmul_tiled(const float* A, const float* B, float* C, int M, int K) {
    extern __shared__ float sdata[];

    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    float acc = 0.0f;
    for (int k = 0; k < K; k += blockDim.z) {
        sdata[threadIdx.y * blockDim.x + threadIdx.x] = A[row * K + k];
        __syncthreads();
        acc += sdata[threadIdx.y * blockDim.x + threadIdx.x] * B[k * blockDim.x + col];
        __syncthreads();
    }

    if (row < M && col < 1) {
        C[row] = acc;
    }
}

std::vector<at::Tensor> matmul_tiled_cuda(const at::Tensor& A, const at::Tensor& B) {
    int M = A.size(0);
    int K = A.size(1);

    auto options = A.options().dtype(at::kFloat);
    auto C = at::empty({M}, options);

    dim3 threads(16, 16, 1);
    dim3 blocks((K + threads.z - 1) / threads.z, (M + threads.y - 1) / threads.y, 1);
    size_t shared_size = threads.x * threads.y * sizeof(float);

    matmul_tiled<<<blocks, threads, shared_size>>>(A.data_ptr<float>(), B.data_ptr<float>(), C.data_ptr<float>(), M, K);

    return {C};
}
"""

# Load the CUDA extension
matmul_tiled_module = load_inline(name="matmul_tiled", sources=[("matmul_tiled.cu", cuda_code)])

class ModelNew(nn.Module):
    def __init__(self):
        super(ModelNew, self).__init__()

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        return matmul_tiled_module.matmul_tiled_cuda(A, B)[0]

def get_inputs():
    A = torch.rand(M, K)
    B = torch.rand(K, 1)
    return [A, B]

def get_init_inputs():
    return []

