import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define the CUDA kernel for batched matrix multiplication
cuda_code = """
#include <torch/extension.h>

#define TILE_SIZE 16

__global__ void bmm_kernel(const float* A, const float* B, float* C, int batch_size, int m, int k, int n) {
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int bx = blockIdx.x, by = blockIdx.y;
    int tx = threadIdx.x, ty = threadIdx.y;

    int row = by * TILE_SIZE + ty;
    int col = bx * TILE_SIZE + tx;

    float Cvalue = 0.0f;

    for (int i = 0; i < (k + TILE_SIZE - 1) / TILE_SIZE; ++i) {
        int Aindex = row * k + i * TILE_SIZE + tx;
        int Bindex = i * TILE_SIZE + ty * n + col;

        As[ty][tx] = (row < m && i * TILE_SIZE + tx < k) ? A[Aindex] : 0.0f;
        Bs[ty][tx] = (i * TILE_SIZE + tx < k && col < n) ? B[Bindex] : 0.0f;

        __syncthreads();

        for (int j = 0; j < TILE_SIZE; ++j) {
            Cvalue += As[ty][j] * Bs[j][tx];
        }

        __syncthreads();
    }

    if (row < m && col < n) {
        C[row * n + col] = Cvalue;
    }
}

std::vector<at::Tensor> bmm_forward(const at::Tensor& A, const at::Tensor& B) {
    int batch_size = A.size(0);
    int m = A.size(1);
    int k = A.size(2);
    int n = B.size(2);

    auto options = A.options();
    auto C = at::empty({batch_size, m, n}, options);

    dim3 grid((n + TILE_SIZE - 1) / TILE_SIZE, (m + TILE_SIZE - 1) / TILE_SIZE);
    dim3 block(TILE_SIZE, TILE_SIZE);

    AT_DISPATCH_FLOATING_TYPES(A.type(), "bmm", ([&] {
        bmm_kernel<<<grid, block>>>(A.data_ptr<scalar_t>(), B.data_ptr<scalar_t>(), C.data_ptr<scalar_t>(), batch_size, m, k, n);
    }));

    return {C};
}
"""

model_new_module = load_inline(name="model_new_module", sources=[("model_new_cuda.cu", cuda_code)])

class ModelNew(nn.Module):
    def __init__(self):
        super(ModelNew, self).__init__()

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        return model_new_module.bmm_forward(A, B)[0]

def get_inputs():
    A = torch.rand(batch_size, m, k)
    B = torch.rand(batch_size, k, n)
    return [A, B]

def get_init_inputs():
    return []

