#include <torch/extension.h>
#include <cuda_runtime.h>

#define TILE_SIZE 16

__global__ void conv_bias_relu_kernel(
    const float* input, 
    const float* weight, 
    const float* bias, 
    float* output, 
    int N, int C, int H, int W, int K, int R, int S
) {
    int n = blockIdx.x;
    int c = blockIdx.y * blockDim.y + threadIdx.y;
    int h = blockIdx.z * blockDim.z + threadIdx.z;

    if (c >= C || h >= H) return;

    float sum = 0.0f;
    for (int k = 0; k < K; ++k) {
        for (int r = 0; r < R; ++r) {
            for (int s = 0; s < S; ++s) {
                int in_idx = n * C * H * W + c * H * W + (h + r) * W + (s + r);
                int wei_idx = c * K * R * S + k * R * S + r * S + s;
                sum += input[in_idx] * weight[wei_idx];
            }
        }
    }

    int bias_idx = c;
    sum += bias[bias_idx];

    int out_idx = n * C * H * W + c * H * W + h * W;
    output[out_idx] = max(sum, 0.0f);
}

std::vector<at::Tensor> conv_bias_relu(const at::Tensor& input, const at::Tensor& weight, const at::Tensor& bias) {
    int N = input.size(0);
    int C = input.size(1);
    int H = input.size(2);
    int W = input.size(3);
    int K = weight.size(0);
    int R = weight.size(2);
    int S = weight.size(3);

    auto options = input.options();
    auto output = at::empty_like(input, options);

    dim3 threads(TILE_SIZE, TILE_SIZE, TILE_SIZE);
    dim3 blocks((W + TILE_SIZE - 1) / TILE_SIZE, (H + TILE_SIZE - 1) / TILE_SIZE, (C + TILE_SIZE - 1) / TILE_SIZE);

    conv_bias_relu_kernel<<<blocks, threads>>>(input.data_ptr<float>(), weight.data_ptr<float>(), bias.data_ptr<float>(), output.data_ptr<float>(), N, C, H, W, K, R, S);

    cudaDeviceSynchronize();
    return {output};
}
