#include <c10/cuda/CUDAContext.h>

__global__ void conv_transpose_bias_add_clamp_scale(
    const float* input, const float* weight, const float* bias,
    float* output, int batch_size, int in_channels, int out_channels,
    int height_in, int width_in, int height_out, int width_out,
    int kernel_size, int stride, int padding, int output_padding,
    float scaling_factor) {
    int b = blockIdx.x;
    int oc = blockIdx.y;
    int oh = blockIdx.z;
    int ow = blockIdx.w;

    int ih_start = oh * stride - padding;
    int iw_start = ow * stride - padding;
    int ih_end = min(ih_start + kernel_size, height_in);
    int iw_end = min(iw_start + kernel_size, width_in);

    float sum = 0.0f;
    for (int ic = 0; ic < in_channels; ++ic) {
        for (int kh = ih_start; kh < ih_end; ++kh) {
            for (int kw = iw_start; kw < iw_end; ++kw) {
                int ih = kh - ih_start;
                int iw = kw - iw_start;
                int idx_input = b * in_channels * height_in * width_in +
                               ic * height_in * width_in +
                               kh * width_in + kw;
                int idx_weight = oc * in_channels * kernel_size * kernel_size +
                                ic * kernel_size * kernel_size +
                                ih * kernel_size + kw;
                sum += input[idx_input] * weight[idx_weight];
            }
        }
    }

    int idx_output = b * out_channels * height_out * width_out +
                    oc * height_out * width_out +
                    oh * width_out + ow;
    output[idx_output] = sum + bias[oc];

    if (output[idx_output] < 0.0f) {
        output[idx_output] = 0.0f;
    } else if (output[idx_output] > 1.0f) {
        output[idx_output] = 1.0f;
    }

    output[idx_output] *= scaling_factor;

    if (output[idx_output] < 0.0f) {
        output[idx_output] = 0.0f;
    } else if (output[idx_output] > 1.0f) {
        output[idx_output] = 1.0f;
    }
}

