import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

class ModelNew(nn.Module):
    def __init__(self):
        super(ModelNew, self).__init__()

    def forward(self, A, B):
        return self.matmul_custom(A, B)

    @staticmethod
    def matmul_custom(A, B):
        N, M, K = A.shape
        K, L = B.shape
        C = torch.zeros((N, M, L), dtype=torch.float32, device=A.device)

        # Load the CUDA kernel
        kernel_code = """
        extern "C" __global__ void matmul_kernel(const float* A, const float* B, float* C, int N, int M, int K, int L) {
            int n = blockIdx.z;
            int m = blockIdx.y * blockDim.y + threadIdx.y;
            int k = blockIdx.x * blockDim.x + threadIdx.x;

            float sum = 0.0f;
            for (int i = 0; i < K; ++i) {
                sum += A[n * M * K + m * K + i] * B[i * L + k];
            }
            C[n * M * L + m * L + k] = sum;
        }
        """

        mod = load_inline(name="matmul", sources=[kernel_code], verbose=True)
        matmul_kernel = mod.matmul_kernel

        # Launch the kernel
        block_size = (16, 16, 1)
        grid_size = ((K + block_size[0] - 1) // block_size[0],
                      (M + block_size[1] - 1) // block_size[1],
                      N)

        matmul_kernel(
            A.contiguous().view(-1).data_ptr(),
            B.contiguous().view(-1).data_ptr(),
            C.contiguous().view(-1).data_ptr(),
            N, M, K, L,
            block=block_size,
            grid=grid_size
        )

        return C

