# Define the CUDA kernel for matrix multiplication
cuda_code = """
#include <torch/extension.h>

#define TILE_SIZE 16

__global__ void matmul_kernel(const float* A, const float* B, float* C, int M, int N, int K) {
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int bx = blockIdx.x, by = blockIdx.y;
    int tx = threadIdx.x, ty = threadIdx.y;

    int Row = by * TILE_SIZE + ty;
    int Col = bx * TILE_SIZE + tx;

    float Cvalue = 0.0f;

    for (int m = 0; m < (K + TILE_SIZE - 1) / TILE_SIZE; ++m) {
        int aBegin = Row * K;
        int bBegin = m * TILE_SIZE * K;

        // Load A and B from global memory to shared memory
        As[ty][tx] = (Row < M && aBegin + tx < K) ? A[aBegin + tx] : 0.0f;
        Bs[ty][tx] = (Col < N && bBegin + ty < K) ? B[bBegin + ty] : 0.0f;

        __syncthreads();

        // Compute C within the tile
        for (int k = 0; k < TILE_SIZE; ++k) {
            Cvalue += As[ty][k] * Bs[k][tx];
        }

        __syncthreads();
    }

    // Write C to global memory
    if (Row < M && Col < N) {
        C[Row * N + Col] = Cvalue;
    }
}

