from torch.cuda.amp import custom_fwd, custom_bwd
import triton
import triton.language as tl

class CustomConv3dFunction(Function):
    @staticmethod
    @custom_fwd(cast_inputs=torch.float32)
    def forward(ctx, input, weight, bias=None):
        ctx.save_for_backward(input, weight, bias)
        output = triton.ops.conv3d_forward(input, weight, bias)
        return output

    @staticmethod
    @custom_bwd
    def backward(ctx, grad_output):
        input, weight, bias = ctx.saved_tensors
        grad_input, grad_weight, grad_bias = triton.ops.conv3d_backward(grad_output, input, weight, bias)
        return grad_input, grad_weight, grad_bias

class CustomSoftmaxFunction(Function):
    @staticmethod
    @custom_fwd(cast_inputs=torch.float32)
    def forward(ctx, input):
        exp_input = torch.exp(input - input.max(dim=1, keepdim=True)[0])
        ctx.save_for_backward(exp_input)
        output = exp_input / exp_input.sum(dim=1, keepdim=True)
        return output

    @staticmethod
    @custom_bwd
    def backward(ctx, grad_output):
        exp_input, = ctx.saved_tensors
        grad_input = grad_output * (exp_input * (grad_output - (grad_output * exp_input).sum(dim=1, keepdim=True)))
        return grad_input

