#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cublas_v2.h>

#define TILE_SIZE 16

__global__ void conv2d_forward_kernel(const float* input, const float* weight, const float* bias, float* output, int N, int C, int H, int W, int K, int R, int S, int P, int Q) {
    int n = blockIdx.z;
    int c = blockIdx.y * TILE_SIZE + threadIdx.y;
    int k = blockIdx.x * TILE_SIZE + threadIdx.x;

    if (c >= K || k >= C) return;

    float sum = 0.0f;
    for (int i = 0; i < R; ++i) {
        for (int j = 0; j < S; ++j) {
            int ih = P + i;
            int iw = Q + j;
            if (ih >= 0 && ih < H && iw >= 0 && iw < W) {
                int ic = c * H * W + ih * W + iw;
                int ik = k * R * S + i * S + j;
                sum += input[ic] * weight[ik];
            }
        }
    }

    if (threadIdx.y == 0 && threadIdx.x == 0) {
        output[n * K * Q * P + k * Q * P + P * Q + 0] = sum + bias[k];
    }
}

