class ConvTransposeHardtanhFunction(Function):
    @staticmethod
    @custom_fwd(cast_inputs=torch.float32)
    def forward(ctx, input, weight, bias, stride, padding, output_padding, groups):
        ctx.save_for_backward(input, weight, bias)
        ctx.stride = stride
        ctx.padding = padding
        ctx.output_padding = output_padding
        ctx.groups = groups
        output = torch.nn.functional.conv_transpose2d(input, weight, bias, stride, padding, output_padding, groups)
        output = torch.nn.functional.hardtanh(output)
        return output

    @staticmethod
    @custom_bwd
    def backward(ctx, grad_output):
        input, weight, bias = ctx.saved_tensors
        grad_input = None
        grad_weight = None
        grad_bias = None

        if ctx.needs_input_grad[0]:
            grad_input = torch.nn.functional.conv_transpose2d(grad_output, weight.flip(2).flip(3), None, ctx.stride, ctx.padding, ctx.output_padding, ctx.groups)

        if ctx.needs_input_grad[1]:
            grad_weight = torch.nn.functional.conv2d(input, grad_output.flip(2).flip(3), None, groups=ctx.groups)

        if ctx.needs_input_grad[2]:
            grad_bias = torch.sum(grad_output, dim=[0, 2, 3])

