import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define the custom CUDA kernel for the combined convolution transpose and elementwise addition
conv_transpose_add_kernel_code = """
#include <torch/extension.h>
#include <cuda_runtime.h>

#define TILE_SIZE 16

__global__ void conv_transpose_add_forward(
    const float* input, int in_channels, int out_channels,
    int depth_in, int height_in, int width_in,
    int depth_out, int height_out, int width_out,
    const float* weight, int kernel_size, int stride, int padding, int output_padding,
    const float* sum_weight, float* output) {
    int d = blockIdx.z * blockDim.z + threadIdx.z;
    int h = blockIdx.y * blockDim.y + threadIdx.y;
    int w = blockIdx.x * blockDim.x + threadIdx.x;

    if (d >= depth_out || h >= height_out || w >= width_out) return;

    float accum[OUT_CHANNELS] = {0};
    for (int c = 0; c < in_channels; ++c) {
        int di = d * stride - padding;
        int hi = h * stride - padding;
        int wi = w * stride - padding;
        for (int kd = 0; kd < kernel_size; ++kd) {
            int id = di + kd;
            if (id >= 0 && id < depth_in) {
                for (int kh = 0; kh < kernel_size; ++kh) {
                    int ih = hi + kh;
                    if (ih >= 0 && ih < height_in) {
                        for (int kw = 0; kw < kernel_size; ++kw) {
                            int iw = wi + kw;
                            if (iw >= 0 && iw < width_in) {
                                int idx_in = (c * depth_in + id) * height_in * width_in + (ih * width_in + iw);
                                int idx_wt = (c * kernel_size + kd) * kernel_size * kernel_size + (kh * kernel_size + kw);
                                accum[c] += input[idx_in] * weight[idx_wt];
                            }
                        }
                    }
                }
            }
        }
    }

    int idx_out = ((d * stride + padding) / stride) * (height_out * width_out) +
                 ((h * stride + padding) / stride) * width_out + (w * stride + padding) / stride;
    output[idx_out] = accum[0] + sum_weight[0];
}

torch::Tensor conv_transpose_add_forward_cuda(
    const torch::Tensor& input, int in_channels, int out_channels,
    int depth_in, int height_in, int width_in,
    int depth_out, int height_out, int width_out,
    const torch::Tensor& weight, int kernel_size, int stride, int padding, int output_padding,
    const torch::Tensor& sum_weight) {
    auto options = torch::TensorOptions().dtype(input.dtype()).device(input.device());
    auto output = torch::empty({depth_out, height_out, width_out}, options);

    dim3 grid((width_out + TILE_SIZE - 1) / TILE_SIZE, (height_out + TILE_SIZE - 1) / TILE_SIZE, (depth_out + TILE_SIZE - 1) / TILE_SIZE);
    dim3 block(TILE_SIZE, TILE_SIZE, TILE_SIZE);

    AT_DISPATCH_FLOATING_TYPES(input.type(), "conv_transpose_add_forward", ([&] {
        conv_transpose_add_forward<<<grid, block>>>(input.data_ptr<scalar_t>(), in_channels, out_channels,
