import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.utils.cpp_extension import load_inline

# Define the fused linear + relu kernel in CUDA
fused_linear_relu_kernel = """
#include <cuda_runtime.h>

__global__ void fused_linear_relu(float* input, float* weight, float* bias, float* output, int batch_size, int input_size, int hidden_size) {
    int tid = threadIdx.x;
    int bid = blockIdx.x;
    int i = bid * blockDim.x + tid;

    if (i >= batch_size * hidden_size) return;

    float sum = 0.0f;
    for (int j = 0; j < input_size; ++j) {
        sum += input[i * input_size + j] * weight[j * hidden_size + i];
    }

    sum += bias[i];

    output[i] = max(sum, 0.0f);
}
"""

# Load the fused kernel
fused_linear_relu_module = load_inline(name="fused_linear_relu", sources=[fused_linear_relu_kernel], extra_cuda_cflags=["-O3"])

class ModelNew(nn.Module):
    def __init__(self, input_size, hidden_layer_sizes, output_size):
        super(ModelNew, self).__init__()
        self.layers = nn.ModuleList()
        current_input_size = input_size

        for hidden_size in hidden_layer_sizes:
            self.layers.append(fused_linear_relu_module.FusedLinearReLU(input_size, hidden_size))
            current_input_size = hidden_size

        self.layers.append(nn.Linear(current_input_size, output_size))

    def forward(self, x):
        for layer in self.layers[:-1]:
            x = layer(x)
        x = self.layers[-1](x)
        return x

# Define the fused linear + relu module
class FusedLinearReLU(nn.Module):
    def __init__(self, input_size, hidden_size):
        super(FusedLinearReLU, self).__init__()
        self.weight = nn.Parameter(torch.randn(hidden_size, input_size))
        self.bias = nn.Parameter(torch.randn(hidden_size))

    def forward(self, x):
        batch_size = x.size(0)
        grid_size = (batch_size * hidden_size + 255) // 256
        fused_linear_relu_module.fused_linear_relu(
            x.contiguous().data_ptr(),
            self.weight.data_ptr(),
            self.bias.data_ptr(),
            x.new_zeros((batch_size, hidden_size)).contiguous().data_ptr(),
            batch_size,
            input_size,
            hidden_size,
            grid=(grid_size, 1, 1),
            block=(256, 1, 1)
        )
        return x

