import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.autograd import Function
from torch.cuda.amp import custom_fwd, custom_bwd

class Conv3dBiasFunction(Function):
    @staticmethod
    @custom_fwd(cast_inputs=torch.float32)
    def forward(ctx, input, weight, bias):
        ctx.save_for_backward(input, weight, bias)
        output = F.conv3d(input, weight, None, stride=1, padding=1, dilation=1, groups=1)
        output += bias
        return output

    @staticmethod
    @custom_bwd
    def backward(ctx, grad_output):
        input, weight, bias = ctx.saved_tensors
        grad_input = F.conv3d(grad_output, weight.flip(2).flip(3).flip(4), None, stride=1, padding=1, dilation=1, groups=1)
        grad_weight = F.conv3d(input.transpose(0, 1), grad_output, None, stride=1, padding=1, dilation=1, groups=input.size(0))
        grad_bias = grad_output.sum((0, 2, 3, 4))
        return grad_input, grad_weight, grad_bias

class ModelNew(nn.Module):
    def __init__(self, in_channels, out_channels, kernel_size, bias_shape):
        super(ModelNew, self).__init__()
        self.conv = nn.Conv3d(in_channels, out_channels, kernel_size)
        self.bias = nn.Parameter(torch.randn(bias_shape))

    def forward(self, x):
        x = Conv3dBiasFunction.apply(x, self.conv.weight, self.bias)
        x = F.relu(x)
        x = F.leaky_relu(x, negative_slope=0.01)
        x = F.gelu(x)
        x = torch.sigmoid(x)
        return x

def get_inputs():
    return [torch.rand(batch_size, in_channels, depth, height, width)]

def get_init_inputs():
    return [in_channels, out_channels, kernel_size, bias_shape]

