import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

model_code = """
#include <torch/extension.h>
#include <cuda_runtime.h>

#define TILE_SIZE 16

__global__ void conv3d_forward(const float* input, const float* weight, float* output, int N, int C, int D, int H, int W, int K, int S, int P) {
    int n = blockIdx.z * blockDim.z + threadIdx.z;
    int c = blockIdx.y * blockDim.y + threadIdx.y;
    int d = blockIdx.x * blockDim.x + threadIdx.x;

    if (n >= N || c >= C || d >= D) return;

    float acc = 0.0f;
    for (int k = 0; k < K; ++k) {
        for (int h = 0; h < H; ++h) {
            for (int w = 0; w < W; ++w) {
                int in_idx = ((n * C + c) * D + d) * H * W + (h * W + w);
                int wei_idx = ((c * K + k) * H + h) * W + w;
                acc += input[in_idx] * weight[wei_idx];
            }
        }
    }
    output[(n * C + c) * D + d] = acc;
}

__global__ void max_pool3d_forward(const float* input, float* output, int N, int C, int D, int H, int W, int KD, int KH, int KW, int SD, int SH, int SW) {
    int n = blockIdx.z * blockDim.z + threadIdx.z;
    int c = blockIdx.y * blockDim.y + threadIdx.y;
    int d = blockIdx.x * blockDim.x + threadIdx.x;

    if (n >= N || c >= C || d >= D) return;

    int max_val = -1e9;
    for (int kd = 0; kd < KD; ++kd) {
        for (int kh = 0; kh < KH; ++kh) {
            for (int kw = 0; kw < KW; ++kw) {
                int in_idx = ((n * C + c) * D + d + kd) * H * W + (kh * W + kw);
                max_val = max(max_val, input[in_idx]);
            }
        }
    }
    output[(n * C + c) * D + d] = max_val;
}

__global__ void avg_pool3d_forward(const float* input, float* output, int N, int C, int D, int H, int W, int KD, int KH, int KW, int SD, int SH, int SW) {
    int n = blockIdx.z * blockDim.z + threadIdx.z;
    int c = blockIdx.y * blockDim.y + threadIdx.y;
    int d = blockIdx.x * blockDim.x + threadIdx.x;

    if (n >= N || c >= C || d >= D) return;

    float sum_val = 0.0f;
    for (int kd = 0; kd < KD; ++kd) {
        for (int kh = 0; kh < KH; ++kh) {
            for (int kw = 0; kw < KW; ++kw) {
                int in_idx = ((n * C + c) * D + d + kd) * H * W + (kh * W + kw);
                sum_val += input[in_idx];
            }
        }
    }
    output[(n * C + c) * D + d] = sum_val / (KD * KH * KW);
}

__global__ void bias_addition(const float* input, const float* bias, float* output, int N, int C, int D) {
    int n = blockIdx.z * blockDim.z + threadIdx.z;
    int c = blockIdx.y * blockDim.y + threadIdx.y;
    int d = blockIdx.x * blockDim.x + threadIdx.x;

    if (n >= N || c >= C || d >= D) return;

    output[(n * C + c) * D + d] = input[(n * C + c) * D + d] + bias[c];
}

__global__ void reduction_sum(const float* input, float* output, int N, int C, int D, int sum_dim) {
    extern __shared__ float sdata[];

    int tid = threadIdx.x;
    int i = blockIdx.x * blockDim.x + threadIdx.x;

    if (i < D) {
        sdata[tid] = input[i];
    } else {
        sdata[tid] = 0.0f;
    }

    __syncthreads();

    for (int s = blockDim.x / 2; s > 0; s >>= 1) {
        if (tid < s) {
            sdata[tid] += sdata[tid + s];
        }
        __syncthreads();
    }

    if (tid == 0) {
        output[blockIdx.x] = sdata[0];
    }
}

torch::Tensor conv3d_forward_cuda(const torch::Tensor& input, const torch::Tensor& weight, int divisor) {
    auto options = torch::TensorOptions().dtype(input.dtype()).device(input.device());
    auto output = torch::zeros({input.size(0), weight.size(0), input.size(2)}, options);

    int N = input.size(0);
    int C = input.size(1);
    int D = input.size(2);
    int H = input.size(3);
    int W = input.size(4);
    int K = weight.size(0);
    int S = 1;
    int P = 0;

    dim3 grid(D, C, N);
    dim3 block(TILE_SIZE, TILE_SIZE, 1);

    conv3d_forward<<<grid, block>>>(input.data_ptr<float>(), weight.data_ptr<float>(), output.data_ptr<float>(), N, C, D, H, W, K, S, P);

    return output / divisor;
}

torch::Tensor max_pool3d_forward_cuda(const torch::Tensor& input, int divisor) {
