    auto options = torch::TensorOptions().dtype(input.dtype()).device(input.device());
    auto output = torch::zeros({input.size(0), input.size(1), input.size(2)}, options);

    int N = input.size(0);
    int C = input.size(1);
    int D = input.size(2);
    int H = input.size(3);
    int W = input.size(4);
    int KD = 2;
    int KH = 2;
    int KW = 2;
    int SD = 2;
    int SH = 2;
    int SW = 2;

    dim3 grid(D, C, N);
    dim3 block(TILE_SIZE, TILE_SIZE, 1);

    avg_pool3d_forward<<<grid, block>>>(input.data_ptr<float>(), output.data_ptr<float>(), N, C, D, H, W, KD, KH, KW, SD, SH, SW);

    return output / divisor;
}

torch::Tensor bias_addition_cuda(const torch::Tensor& input, const torch::Tensor& bias) {
    auto options = torch::TensorOptions().dtype(input.dtype()).device(input.device());
    auto output = torch::zeros_like(input, options);

    int N = input.size(0);
    int C = input.size(1);
    int D = input.size(2);

    dim3 grid(D, C, N);
    dim3 block(TILE_SIZE, TILE_SIZE, 1);

    bias_addition<<<grid, block>>>(input.data_ptr<float>(), bias.data_ptr<float>(), output.data_ptr<float>(), N, C, D);

    return output;
}

torch::Tensor reduction_sum_cuda(const torch::Tensor& input, int sum_dim) {
    auto options = torch::TensorOptions().dtype(input.dtype()).device(input.device());
    auto output = torch::zeros({input.size(0), input.size(1)}, options);

    int N = input.size(0);
    int C = input.size(1);
    int D = input.size(2);

    dim3 grid(C, N, 1);
    dim3 block(TILE_SIZE, 1, 1);

    size_t smem_size = TILE_SIZE * sizeof(float);

    reduction_sum<<<grid, block, smem_size>>>(input.data_ptr<float>(), output.data_ptr<float>(), N, C, D, sum_dim);

    return output;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("conv3d_forward", &conv3d_forward_cuda, "3D convolution forward");
    m.def("max_pool3d_forward", &max_pool3d_forward_cuda, "3D max pooling forward");
    m.def("avg_pool3d_forward", &avg_pool3d_forward_cuda, "3D average pooling forward");
    m.def("bias_addition", &bias_addition_cuda, "Bias addition");
    m.def("reduction_sum", &reduction_sum_cuda, "Reduction sum");
}
