custom_ops = load_inline(model_code)

class ModelNew(nn.Module):
    def __init__(self, in_channels, out_channels, kernel_size, divisor, pool_size, bias_shape, sum_dim):
        super(ModelNew, self).__init__()
        self.conv_weight = nn.Parameter(torch.randn(out_channels, in_channels, *kernel_size))
        self.divisor = divisor
        self.bias = nn.Parameter(torch.randn(bias_shape))

    def forward(self, x):
        x = custom_ops.conv3d_forward(x, self.conv_weight, self.divisor)
        x = custom_ops.max_pool3d_forward(x, self.divisor)
        x = custom_ops.avg_pool3d_forward(x, self.divisor)
