    const int row = blockIdx.y * blockDim.y + threadIdx.y;
    const int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < m && col < n) {
        float sum = 0.0f;
        for (int i = 0; i < k; ++i) {
            sum += input[row * k + i] * weight[i * n + col];
        }
        sum += bias[col];
        output[row * n + col] = sum > 0 ? sum : 0.0f;
    }
}

