from torch.autograd import Function
from torch.cuda.amp import custom_fwd, custom_bwd

class MatMulBiasReLUFunction(Function):
    @staticmethod
    @custom_fwd(cast_inputs=torch.float32)
    def forward(ctx, input, weight, bias):
        ctx.save_for_backward(input, weight, bias)
        output = torch.matmul(input, weight) + bias
        ctx.output = output.clone()
        return F.relu(output)

    @staticmethod
    @custom_bwd
    def backward(ctx, grad_output):
        input, weight, bias = ctx.saved_tensors
        grad_input = None
        grad_weight = None
        grad_bias = None

        if ctx.needs_input_grad[0]:
            grad_input = torch.matmul(grad_output, weight.t())
        if ctx.needs_input_grad[1]:
            grad_weight = torch.matmul(input.t(), grad_output)
        if ctx.needs_input_grad[2]:
            grad_bias = torch.sum(grad_output, dim=0)

        return grad_input, grad_weight, grad_bias

