                int ih = h + kh - 1;
                int iw = w + kw - 1;
                if (ih >= 0 && ih < height && iw >= 0 && iw < width) {
                    int i_idx = b * in_channels * height * width + c * height * width + ih * width + iw;
                    int w_idx = o * in_channels * 3 * 3 + c * 3 * 3 + kh * 3 + kw;
