__global__ void conv2d_fp32(const float* input, const float* weight, float* output, int N, int C_in, int H_in, int W_in, int C_out, int H_out, int W_out, int pad_h, int pad_w, int stride_h, int stride_w) {
    int n = blockIdx.x;
    int c_out = blockIdx.y;
    int h_out = blockIdx.z;
    int w_out = blockIdx.w;

    int h_in_start = h_out * stride_h - pad_h;
    int w_in_start = w_out * stride_w - pad_w;

    float sum = 0.0f;
    for (int c_in = 0; c_in < C_in; ++c_in) {
        for (int h_in = 0; h_in < H_in; ++h_in) {
            for (int w_in = 0; w_in < W_in; ++w_in) {
                int h_in_idx = h_in_start + h_in;
                int w_in_idx = w_in_start + w_in;
                if (h_in_idx >= 0 && h_in_idx < H_in && w_in_idx >= 0 && w_in_idx < W_in) {
                    int input_idx = n * C_in * H_in * W_in + c_in * H_in * W_in + h_in_idx * W_in + w_in_idx;
                    int weight_idx = c_out * C_in * H_in * W_in + c_in * H_in * W_in + h_in * W_in + w_in;
                    sum += input[input_idx] * weight[weight_idx];
                }
            }
        }
    }

    int output_idx = n * C_out * H_out * W_out + c_out * H_out * W_out + h_out * W_out + w_out;
    output[output_idx] = sum;
}
