__global__ void batch_norm_fp32(const float* input, float* output, const float* mean, const float* var, const float* gamma, const float* beta, int N, int C, int H, int W, float eps) {
    int n = blockIdx.x;
    int c = blockIdx.y;
    int h = blockIdx.z;
    int w = blockIdx.w;

    int idx = n * C * H * W + c * H * W + h * W + w;
    float x_hat = (input[idx] - mean[c]) / sqrt(var[c] + eps);
    output[idx] = gamma[c] * x_hat + beta[c];
}
