matmul_bias_relu_kernel_code = """
__global__ void matmul_bias_relu_fp32(const float* input, const float* weight, const float* bias, float* output, int M, int N, int K) {
    int m = blockIdx.x * blockDim.x + threadIdx.x;
    int n = blockIdx.y * blockDim.y + threadIdx.y;

    if (m < M && n < N) {
        float sum = bias[n];
        for (int k = 0; k < K; ++k) {
            sum += input[m * K + k] * weight[k * N + n];
        }
        output[m * N + n] = max(sum, 0.0f);
    }
}
