#include <iostream>
#include <vector>

struct ElementwiseMulOp {
    static void run(float* input, float scalar, float* output, int M, int N) {
        for (int i = 0; i < M; ++i) {
            for (int j = 0; j < N; ++j) {
                output[i * N + j] = input[i * N + j] * scalar;
