#include <torch/extension.h>

void elementwise_mul_forward_cuda(torch::Tensor input, float scalar, torch::Tensor output) {
    const auto M = input.size(0);
    const auto N = input.size(1);

    #pragma omp parallel for collapse(2)
    for (int i = 0; i < M; ++i) {
        for (int j = 0; j < N; ++j) {
            output[i * N + j] = input[i * N + j] * scalar;
        }
    }
}

void elementwise_mul_backward_cuda(torch::Tensor grad_output, float scalar, torch::Tensor grad_input) {
    const auto M = grad_output.size(0);
    const auto N = grad_output.size(1);

    #pragma omp parallel for collapse(2)
    for (int i = 0; i < M; ++i) {
        for (int j = 0; j < N; ++j) {
            grad_input[i * N + j] = grad_output[i * N + j] * scalar;
        }
    }
}
"""

