    @staticmethod
    @custom_fwd(cast_inputs=torch.float32)
    def forward(ctx, input, scalar):
        ctx.save_for_backward(input, scalar)
        output = torch.empty_like(input, device=input.device)
        elementwise_mul_forward_cuda(input, scalar, output)
        return output

    @staticmethod
    @custom_bwd
    def backward(ctx, grad_output):
        input, scalar = ctx.saved_tensors
        grad_input = torch.empty_like(input, device=input.device)
        elementwise_mul_backward_cuda(grad_output, scalar, grad_input)
        return grad_input, None

