    def __init__(self):
        super(ModelNew, self).__init__()

    def forward(self, A: torch.Tensor, s: float) -> torch.Tensor:
        return ElementwiseMulFunction.apply(A, s)

def get_inputs():
    A = torch.rand(16384 * 4, 4096 * 4)
    s = 3.14
    return [A, s]

