__global__ void gemm_tiled_kernel(const float* A, const float* B, float* C, int M, int K, int N, float alpha, float beta) {
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    float cvalue = (beta == 0.0f) ? 0.0f : C[row * N + col];

    for (int m = 0; m < K; m += TILE_SIZE) {
        if (row < M && m + threadIdx.y < K) {
            As[threadIdx.y][threadIdx.x] = A[row * K + m + threadIdx.y];
        } else {
            As[threadIdx.y][threadIdx.x] = 0.0f;
        }

        if (col < N && m + threadIdx.x < K) {
            Bs[threadIdx.y][threadIdx.x] = B[(m + threadIdx.x) * N + col];
        } else {
            Bs[threadIdx.y][threadIdx.x] = 0.0f;
        }

        __syncthreads();

        for (int k = 0; k < TILE_SIZE; ++k) {
            cvalue += As[threadIdx.y][k] * Bs[k][threadIdx.x];
        }

        __syncthreads();
