#include <torch/torch.h>

#define MISH_INPUT_THRESHOLD 0.5f

// Fusion of two Mish activations into one kernel
void mish_forward(torch::Tensor input, torch::Tensor output) {
    auto input_ptr = input.data_ptr<float>();
    auto output_ptr = output.data_ptr<float>();

    const int numel = input.numel();
    #pragma omp parallel for
    for (int i = 0; i < numel; ++i) {
        float val = input_ptr[i];
        if (val >= MISH_INPUT_THRESHOLD) {
            output_ptr[i] = val * std::tanh(std::exp(val));
        } else {
            output_ptr[i] = val + ((std::exp(2.0 * val) - 1.0) * val / (std::exp(2.0 * val) + 1.0));
        }
    }
}
