#include <torch/extension.h>
#include <cuda_runtime.h>

#define TILE_SIZE 16

__global__ void fused_softmax_cuda(torch::Tensor input, torch::Tensor output, float temperature) {
    int batch_idx = blockIdx.x;
    int channel_idx = blockIdx.y * TILE_SIZE + threadIdx.y;

    extern __shared__ float shmem[];

    float* local_input = shmem;
    float* local_output = shmem + TILE_SIZE * TILE_SIZE;

    int num_elements = input.size(2) * input.size(3) * input.size(4);
    for (int i = 0; i < num_elements; i += TILE_SIZE) {
        int idx = blockIdx.z * blockDim.z + threadIdx.z;
        if (idx < num_elements) {
            local_input[idx] = input[batch_idx][channel_idx][i / input.size(2)][i / input.size(3)][i % input.size(3)];
        }
    }

    __syncthreads();

    float row_max = -__FLT_MAX__;
    for (int i = 0; i < TILE_SIZE; ++i) {
        row_max = max(row_max, local_input[i]);
    }

    __syncthreads();

    float sum_exp = 0.0f;
    for (int i = 0; i < TILE_SIZE; ++i) {
        local_input[i] -= row_max;
        local_input[i] = exp(local_input[i] * temperature);
        sum_exp += local_input[i];
    }

    __syncthreads();

    float inv_sum_exp = 1.0f / sum_exp;
    for (int i = 0; i < TILE_SIZE; ++i) {
        local_output[i] = local_input[i] * inv_sum_exp;
    }

    __syncthreads();

    for (int i = 0; i < num_elements; i += TILE_SIZE) {
        int idx = blockIdx.z * blockDim.z + threadIdx.z;
        if (idx < num_elements) {
            output[batch_idx][channel_idx][i / input.size(2)][i / input.size(3)][i % input.size(3)] = local_output[idx];
        }
    }
}

torch::Tensor fused_softmax(torch::Tensor input, float temperature) {
    int batch_size = input.size(0);
    int channels = input.size(1);
    int depth = input.size(2);
    int height = input.size(3);
    int width = input.size(4);

    auto options = torch::TensorOptions().dtype(input.dtype()).device(input.device());
    torch::Tensor output = torch::empty_like(input, options);

    int blocks_per_grid_x = (batch_size + TILE_SIZE - 1) / TILE_SIZE;
    int blocks_per_grid_y = (channels + TILE_SIZE - 1) / TILE_SIZE;
    int blocks_per_grid_z = (depth * height * width + TILE_SIZE - 1) / TILE_SIZE;

    fused_softmax_cuda<<<dim3(blocks_per_grid_x, blocks_per_grid_y, blocks_per_grid_z), dim3(TILE_SIZE, TILE_SIZE, TILE_SIZE), sizeof(float) * TILE_SIZE * TILE_SIZE * 2>>>(input.contiguous(), output.contiguous(), temperature);

