import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cpp_sources = """
#include <torch/extension.h>
#include <cuda_runtime.h>

__global__ void fused_matmul_relu_kernel(
    const float* input, const float* weight, const float* bias,
    float* output, int batch_size, int in_features, int out_features, float subtract_value, float multiply_value) {
    int tid = threadIdx.x;
    int bid = blockIdx.x;

    extern __shared__ float s[];
    float* s_input = s + tid * in_features;
    float* s_weight = s + tid * out_features;

    // Load data into shared memory
    s[tid] = input[bid * in_features + tid];
    s_input[tid] = weight[tid * out_features + tid];
    s_weight[tid] = weight[tid * out_features + tid];

    __syncthreads();

    float sum = 0.0f;
    for (int k = 0; k < in_features; ++k) {
        sum += s_input[k] * s_weight[k];
    }

    float val = sum - subtract_value;
    val *= multiply_value;
    val = val > 0 ? val : 0; // ReLU

    // Store result back to global memory
    output[bid * out_features + tid] = val;
}

std::vector<at::Tensor> fused_matmul_relu_forward(
    at::Tensor input, at::Tensor weight, at::Tensor bias, float subtract_value, float multiply_value) {
    auto output = at::empty_like(input);
    int batch_size = input.size(0);
    int in_features = input.size(1);
    int out_features = weight.size(1);

    const int threads_per_block = 256;
    const int blocks_per_grid = (batch_size + threads_per_block - 1) / threads_per_block;

    fused_matmul_relu_kernel<<<blocks_per_grid, threads_per_block, threads_per_block * sizeof(float)>>>(
        input.data_ptr<float>(), weight.data_ptr<float>(), bias.data_ptr<float>(),
        output.data_ptr<float>(), batch_size, in_features, out_features, subtract_value, multiply_value);

    return {output};
}
"""

class ModelNew(nn.Module):
    def __init__(self, in_features, out_features, subtract_value, multiply_value):
        super(ModelNew, self).__init__()
        self.linear = nn.Linear(in_features, out_features)
        self.subtract_value = subtract_value
        self.multiply_value = multiply_value

    def forward(self, x):
        x = self.linear(x)
        x = x.contiguous()
        output = fused_matmul_relu_forward(x, self.linear.weight, self.linear.bias, self.subtract_value, self.multiply_value)[0]
        return output

def get_inputs():
    return [torch.rand(batch_size, in_features)]

def get_init_inputs():
    return [in_features, out_features, subtract_value, multiply_value]

