#include <torch/extension.h>

namespace {

template <typename scalar_t>
void relu_batchnorm_cuda_kernel(const int N, const scalar_t* x, const scalar_t* weight, 
                                const scalar_t* bias, const scalar_t* running_mean, 
                                const scalar_t* running_var, scalar_t* y, scalar_t* mean, 
                                scalar_t* var, float eps, float momentum) {
    const scalar_t* x_ptr = x;
    scalar_t* y_ptr = y;

    for (int i = 0; i < N; ++i) {
        scalar_t val = *x_ptr++;
        scalar_t norm_val = (val - running_mean[i % N]) / sqrt(running_var[i % N] + eps);
        scalar_t act_val = std::max(norm_val * weight[i % N], static_cast<scalar_t>(0));
        *y_ptr++ = act_val + (bias ? bias[i % N] : 0);
        *mean++ = norm_val * weight[i % N];
        *var++ = act_val * act_val;
    }
}

